mapper.select:
SELECT c.id, c.course_code, c.course_name, c.course_type, c.credit, c.hours, c.semester_id, c.department_id, c.teacher_name, c.description, c.status, c.created_at, d.dept_name as department_name, s.semester_name FROM courses c LEFT JOIN departments d ON c.department_id = d.id LEFT JOIN semesters s ON c.semester_id = s.id WHERE c.deleted = 0
AND c.course_code LIKE CONCAT('%', #{query.courseCode}, '%')
AND c.course_name LIKE CONCAT('%', #{query.courseName}, '%')
AND c.course_type = #{query.courseType}
AND c.semester_id = #{query.semesterId}
AND c.department_id = #{query.departmentId}
AND c.status = #{query.status}
ORDER BY c.course_code

SELECT DISTINCT c.id, c.course_code, c.course_name, c.course_type, c.credit, c.hours, c.teacher_name FROM courses c INNER JOIN student_scores ss ON c.id = ss.course_id INNER JOIN students s ON ss.student_id = s.id WHERE s.class_id = #{classId}
AND ss.semester_id = #{semesterId}
AND c.deleted = 0 AND ss.deleted = 0 ORDER BY c.course_code

SELECT COUNT(*) FROM student_scores
WHERE course_id = #{courseId}
AND deleted = 0
